parameters.jsCode:
// Generate 2 thumbnail concepts with adaptive style selection
// v3 (2026-04-30 phase 2): rhetorical-question / headline / multi-line text formats,
// hard variety enforcement, expanded character budgets.
var topicArr = $('Fetch Topic').first().json;
var topic = Array.isArray(topicArr) ? topicArr[0] : topicArr;
var topicId = $('Webhook Trigger').first().json.body.topic_id;
var title = topic.seo_title || topic.original_title;
var hook = topic.narrative_hook || '';
var projectId = topic.project_id;
var countryTarget = (topic.country_target || 'GENERAL').toUpperCase();

var projResp = await fetch(
  $env.SUPABASE_URL + '/rest/v1/projects?id=eq.' + projectId + '&select=niche',
  { headers: { 'apikey': $env.SUPABASE_ANON_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY } }
);
var projData = await projResp.json();
var niche = (Array.isArray(projData) && projData[0]) ? projData[0].niche : '';

var registerId = topic.production_register || '';
var registerEra = topic.register_era_detected || '';
var registerGrade = 'teal-orange color grade (Hollywood blockbuster standard)';
var registerAccent = '';
if (registerId) {
  try {
    var rResp = await fetch(
      $env.SUPABASE_URL + '/rest/v1/production_registers?register_id=eq.' + registerId + '&select=config,accent_color_hex',
      { headers: { 'apikey': $env.SUPABASE_ANON_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY } }
    );
    var rData = await rResp.json();
    if (Array.isArray(rData) && rData[0]) {
      registerAccent = rData[0].accent_color_hex || '';
    }
  } catch (e) { /* non-fatal */ }
}
var REGISTER_GRADE_OVERRIDES = {
  REGISTER_01_ECONOMIST: 'muted editorial documentary color grade with controlled warmth, amber midtones, subtle shadow cooling (Johnny Harris / Wendover documentary look)',
  REGISTER_02_PREMIUM: 'Kodak Portra 400 color grade with teal shadows, amber highlights, and generous golden hour warmth (Bloomberg Originals luxury editorial)',
  REGISTER_03_NOIR: 'bleach-bypass desaturated color grade with deep crushed blacks and cold blue shadows, low saturation, noir chiaroscuro (LEMMiNO / Netflix Dirty Money noir)',
  REGISTER_04_SIGNAL: 'clinical cool color grade with blue-black shadows, cyan highlights, and high contrast for tech precision (Apple keynote / ColdFusion tech documentary)',
  REGISTER_05_ARCHIVE: 'sepia-faded warm color grade with lifted shadows, low saturation, and period archival patina (Ken Burns documentary / mid-century Kodachrome)'
};
if (registerId && REGISTER_GRADE_OVERRIDES[registerId]) {
  registerGrade = REGISTER_GRADE_OVERRIDES[registerId];
}

var nicheEmotions = {
  betrayal_revenge: { single_a: 'jaw-dropped shock, eyes wide, mouth agape, one tear rolling down cheek', single_b: 'cold calculating fury, narrowed eyes, clenched jaw, veins visible on temple', dual_left: 'sinister smirk, one eyebrow raised, knowing look, slight head tilt', dual_right: 'devastated shock, wide tearful eyes, hand over mouth, crumbling composure', scene_bg: 'a shattered family photo frame on a dark wooden table, broken glass, dramatic volumetric light beam', antagonist_kind: 'human' },
  legal_court: { single_a: 'stunned disbelief, wide eyes, raised eyebrows, mouth slightly open', single_b: 'stern suspicious glare, furrowed brows, piercing side-eye, jaw set tight', dual_left: 'aggressive prosecutor pointing finger, intense focused stare, sharp suit', dual_right: 'panicked defendant, sweat on forehead, loosened tie, darting fearful eyes', scene_bg: 'empty dramatic courtroom interior, dark wood, single volumetric spotlight on witness stand', antagonist_kind: 'human' },
  true_crime: { single_a: 'haunted thousand-yard stare, hollow glistening eyes, single tear, jaw clenched with fierce determination', single_b: 'intense detective scrutiny, one eyebrow raised, skeptical frown, sharp analytical gaze', dual_left: 'cold emotionless criminal stare, dead eyes, slight smirk, unflinching', dual_right: 'determined detective, sharp analytical gaze, slight lean forward, badge visible', scene_bg: 'dimly lit evidence room, red string connecting photos on corkboard, volumetric light beam cutting through dusty air', antagonist_kind: 'human' },
  finance_education: { single_a: 'wide-eyed realization with brows lifted, mouth slightly open, dawning understanding while looking down at a calculator screen showing a meaningful number', single_b: 'confident calm focus with a slight knowing smile, looking directly at camera while holding a small relevant document', dual_left: 'frustrated past-self at a worn desk, head propped in one hand, looking down at a stack of bills or unopened government letters with an exhausted expression', dual_right: 'empowered present-self upright with a slight relieved smile, holding a folder or document, posture confident and at ease', scene_bg: 'editorial flat-lay of a calculator, an opened government letter, a magnifying glass, and a green highlighter on a worn wooden desk under a single warm desk lamp', antagonist_kind: 'abstract' },
  government_benefits: { single_a: 'wide-eyed quiet realization, hand on chin, eyes scanning a benefits letter, expression that reads as why-didnt-I-know-this', single_b: 'composed quiet determination with a slight smile, holding a benefits card or government letter, looking forward with calm agency', dual_left: 'tired person at a kitchen table, brows furrowed, palms up over a confusing benefits form, exhausted by the system â€” represents the past version who did not know', dual_right: 'same person now informed and at ease, holding the benefits card with a small confident smile â€” represents the present version who knows their entitlements', scene_bg: 'editorial flat-lay of a government benefits letter, a benefits card, a calculator showing a saved amount, and a small green checkmark folder on a worn wooden desk under single warm window light', antagonist_kind: 'abstract' },
  transformation: { single_a: 'before-state: drained, hunched, low-energy, looking down with subdued cool lighting', single_b: 'after-state: confident, upright, looking forward with sharp directional warm light and clearer eyes', dual_left: 'before: tired, slumped, low-energy expression with cool subdued lighting', dual_right: 'after: same person transformed â€” energized, focused, sharper eyes, brighter golden rim light', scene_bg: 'editorial split-context environment showing a journey from disorder to order, soft directional light', antagonist_kind: 'abstract' },
  tech_explainer: { single_a: 'curious focused expression, slight head tilt, eyes locked on a glowing screen with cyan-blue rim light', single_b: 'confident knowing slight smile, hand near chin in a thinking pose, sharp directional key light', dual_left: 'startled or confused user, brows furrowed, looking at a screen with an unfamiliar interface', dual_right: 'composed expert with calm confident expression, looking directly at camera, soft key light', scene_bg: 'a clean modern desk with a single monitor showing an abstract data visualization, soft cyan rim light', antagonist_kind: 'abstract' },
  historical_documentary: { single_a: 'thoughtful contemplative expression, hand on chin, soft window light from camera-left, subtle gravitas', single_b: 'stern resolute expression, direct camera gaze, hard directional key light from camera-right, soft fill on shadow side', dual_left: 'period-appropriate authority figure with stern expression and direct gaze', dual_right: 'period-appropriate witness or chronicler with thoughtful contemplative expression looking off-camera', scene_bg: 'period-appropriate location reference â€” book-lined library, archival room, or historic building interior â€” single window light', antagonist_kind: 'human' }
};

var nicheKey = 'historical_documentary';
var nicheLower = (niche || '').toLowerCase();
if (nicheLower === 'super_au' || nicheLower.includes('centrelink') || nicheLower.includes('healthcare card') || nicheLower.includes('aussie super') || nicheLower.includes('australian super') || nicheLower.includes('age pension') || nicheLower.includes('pension loan')) {
  nicheKey = 'government_benefits';
}
else if (nicheLower.includes('credit card') || nicheLower.includes('finance') || nicheLower.includes('money') || nicheLower.includes('wealth') || nicheLower.includes('tax') || nicheLower.includes('investing') || nicheLower.includes('retirement') || nicheLower.includes('budget') || nicheLower.includes('savings')) {
  nicheKey = 'finance_education';
}
else if (nicheLower.includes('legal') || nicheLower.includes('court') || nicheLower.includes('lawsuit')) {
  nicheKey = 'legal_court';
}
else if (nicheLower.includes('crime') || nicheLower.includes('serial') || nicheLower.includes('heist') || nicheLower.includes('unsolved') || nicheLower.includes('cold case')) {
  nicheKey = 'true_crime';
}
else if (nicheLower.includes('betrayal') || nicheLower.includes('scandal') || nicheLower.includes('drama') || nicheLower.includes('divorce') || nicheLower.includes('infidelity')) {
  nicheKey = 'betrayal_revenge';
}
else if (nicheLower.includes('tech') || nicheLower.includes('programming') || nicheLower.includes('coding') || nicheLower.includes('cloud') || nicheLower.includes('aws') || nicheLower.includes('docker') || nicheLower.includes(' ai ') || nicheLower.startsWith('ai ') || nicheLower.endsWith(' ai')) {
  nicheKey = 'tech_explainer';
}
else if (nicheLower.includes('fitness') || nicheLower.includes('weight') || nicheLower.includes('habit') || nicheLower.includes('productivity') || nicheLower.includes('transformation') || nicheLower.includes('learning')) {
  nicheKey = 'transformation';
}
else if (nicheLower.includes('history') || nicheLower.includes('historical') || nicheLower.includes('ancient') || nicheLower.includes('medieval') || nicheLower.includes('archive')) {
  nicheKey = 'historical_documentary';
}
if (countryTarget === 'AU' && (nicheKey === 'betrayal_revenge' || nicheKey === 'legal_court')) {
  if (nicheLower.includes('finance') || nicheLower.includes('super') || nicheLower.includes('centrelink') || nicheLower.includes('benefit') || nicheLower.includes('tax')) {
    nicheKey = 'government_benefits';
  }
}

var emotions = nicheEmotions[nicheKey];
var antagonistKind = emotions.antagonist_kind || 'human';
console.log('Thumbnail concept routing: niche=' + niche + ' country=' + countryTarget + ' -> nicheKey=' + nicheKey + ' antagonist=' + antagonistKind + ' register=' + registerId);

var representationBlock = '';
if (countryTarget === 'AU') {
  representationBlock = ''
    + '   COUNTRY REPRESENTATION (Australia, MANDATORY):\n'
    + '   - Render diverse modern Australian features. Mix subjects across thumbnails: Aboriginal & Torres Strait Islander, Asian-Australian, Pacific Islander, Mediterranean-Australian, and Anglo-Australian heritage.\n'
    + '   - Do NOT default to a generic Western middle-aged white face for every prompt.\n'
    + '   - Do NOT depict any recognizable real Australian politician, judge, MP, AFP officer, ATO commissioner, or other public official.\n'
    + '   - For finance/benefits/super topics, the antagonist is NEVER a person â€” it is the system, the paperwork, or the rule book.\n\n';
} else if (countryTarget === 'US') {
  representationBlock = ''
    + '   COUNTRY REPRESENTATION (United States, MANDATORY):\n'
    + '   - Render diverse modern American features. Mix subjects across thumbnails: African-American, Latinx, Asian-American, Native American, and white American heritage.\n'
    + '   - Do NOT default to a generic Western middle-aged white face for every prompt.\n'
    + '   - Do NOT depict any recognizable real US politician, judge, federal official, or other public figure.\n\n';
}

var antagonistInstruction = '';
if (antagonistKind === 'abstract') {
  antagonistInstruction = ''
    + '   ANTAGONIST IS ABSTRACT (NOT a person):\n'
    + '   - For dual_face: BOTH faces are sympathetic versions of the same protagonist (past-self vs present-self / before vs after / confused vs informed). Neither face should look sinister, manipulative, or villainous.\n'
    + '   - For scene_overlay: the wide background scene represents the abstract antagonist (paperwork chaos, an indecipherable benefits form, a broken system, etc.) â€” NOT a human figure.\n'
    + '   - Do NOT render sinister officials, smirking authorities, or villain-coded characters.\n\n';
} else {
  antagonistInstruction = ''
    + '   ANTAGONIST CHARACTERIZATION:\n'
    + '   - Antagonist may be a human character (per emotion profile) but must be a generic stand-in, NEVER a likeness of a real public figure.\n\n';
}

var promptText = 'You are an elite YouTube thumbnail strategist for documentary channels (12%+ CTR).\n\n'
  + 'VIDEO TITLE: "' + title + '"\n'
  + 'HOOK: "' + hook + '"\n'
  + 'NICHE: "' + niche + '" (resolved profile: ' + nicheKey + ', country: ' + countryTarget + ')\n'
  + 'PRODUCTION REGISTER: ' + (registerId || 'GENERIC') + (registerEra ? ' (' + registerEra + ')' : '') + '\n\n'
  + 'You must generate 2 thumbnail concepts.\n\n'
  + 'STYLE OPTIONS (the visual layout):\n'
  + '1. "single_face" â€” One person\'s face filling 65% of RIGHT side of frame. Left third is empty dark space for text overlay. Best for personal stories and shocking reveals.\n'
  + '2. "dual_face" â€” Two faces side by side with dark divider. Best for conflict, BEFORE/AFTER framing, past-self vs present-self framing.\n'
  + '3. "scene_overlay" â€” Wide cinematic scene as background with a person\'s face overlaid in the lower-right corner (40% of frame). Upper-left quadrant darker for text. Best for location-based stories or abstract-antagonist topics.\n\n'
  + 'TEXT FORMAT OPTIONS (the hero text shape):\n'
  + '- "stack": punchy 1-3 single-word vertical stack. Each line is ONE word. Best for shocking facts, single concepts, dollar-amount reveals. (DEFAULT for most topics.)\n'
  + '- "question": 2-4 line rhetorical question that hooks curiosity. Each line up to 18 chars. Last line MUST end with "?". Best for explainer/educational topics where the viewer must click to get the answer.\n'
  + '- "headline": 1-3 line bold headline phrase, like a magazine cover. Each line up to 22 chars. Best for breaking news, big claims, named-program reveals.\n'
  + '- "scroll_stopper": 4-5 line bold headline broken across multiple short lines (each up to 14 chars), with ALTERNATING accent + white words. Total title length 40-55 chars. Best for high-stakes investigative reveals where a longer title is needed and you want maximum scroll-stop. Lines wrap by emphasis word (e.g. "HOW THE / INTERCHANGE / FEE / BECAME / AMERICA\u0027S / HIDDEN TAX" â€” 6 lines alternating yellow + white).\n\n'
  + 'STYLE Ã— FORMAT FIT GUIDE (use this when picking):\n'
  + '- single_face has the SMALLEST text width budget (~480 px). Stick to "stack" 2-3 single words, OR a "question" with very short lines (â‰¤14 chars).\n'
  + '- dual_face and scene_overlay have wider text bands (~1200 / 850 px). Both formats fit comfortably; choose based on title intent.\n\n'
  + 'STYLE/FORMAT VARIETY (HARD RULE):\n'
  + '- Concept A and Concept B MUST use DIFFERENT styles AND DIFFERENT formats. Two different visual layouts AND two different text formats â€” this gives a real A/B test, not a palette swap. If the title only fits one style well, still pick two different styles and adapt the prompt; better to have an imperfect-but-different B than two near-identical thumbnails.\n\n'
  + 'For EACH concept provide a JSON object with these fields:\n\n'
  + '1. style: "single_face" | "dual_face" | "scene_overlay"\n'
  + '2. text_format: "stack" | "question" | "headline" | "scroll_stopper"\n'
  + '3. text_lines: array of strings â€” the lines as they should appear on the thumbnail, ALL UPPERCASE.\n'
  + '   - stack: 1-3 entries, each ONE word, max 10 chars per line.\n'
  + '   - question: 2-4 entries, each up to 18 chars per line. Last entry MUST end with "?".\n'
  + '   - headline: 1-3 entries, each up to 22 chars per line.\n'
  + '   - scroll_stopper: 4-6 entries, each up to 14 chars per line. Total characters across all lines: 40-55. Break the title at natural emphasis points so alternating-color rendering reads cleanly (every other line is the accent color).\n'
  + '4. emphasis_index: which line gets color emphasis (0-based).\n'
  + '5. image_prompts: array of Fal.ai Seedream 4.5 prompts (1 for single_face, 2 for dual_face/scene_overlay â€” see size rules below).\n\n'
  + '   IMAGE SIZE RULES (per style):\n'
  + '   - single_face: 1 prompt at 1280x720 landscape, face fills 65% of RIGHT side, left third pitch-black for text.\n'
  + '   - dual_face: 2 prompts each at 640x720 portrait, face fills 80%. First = LEFT person, second = RIGHT person.\n'
  + '   - scene_overlay: prompt 1 = wide 1280x720 scene with NO people, upper-left darker for text; prompt 2 = 480x480 tight face portrait for the inset.\n\n'
  + '   === CRITICAL: PHOTOREALISTIC IMAGE RULES (MANDATORY) ===\n'
  + '   Every prompt MUST start with: "Ultra-realistic DSLR photograph, candid documentary moment, shot on Canon EOS R5 85mm f/1.2"\n'
  + '   Every prompt MUST end with: "8K resolution, RAW unprocessed photograph, photorealistic, NOT illustration, NOT painting, NOT sketch, NOT anime, NOT digital art, NOT 3D render, NOT cinematic still" followed by crop dimensions.\n\n'
  + '   Skin texture (MANDATORY in every face prompt â€” explicitly defeats the AI smoothing baseline):\n'
  + '   - Visible skin pores on cheeks, forehead, and nose\n'
  + '   - Stray hair fibers, fine facial hair stubble or peach fuzz visible\n'
  + '   - Subtle natural skin imperfections â€” moles, fine lines, faint redness â€” NOT smoothed or airbrushed\n'
  + '   - Skin is NOT plasticized, NOT softened, NOT retouched â€” documentary unretouched quality\n\n'
  + '   Lighting (MANDATORY in every face prompt):\n'
  + '   - Studio rim lighting from behind creating golden edge light on hair and shoulders\n'
  + '   - Dramatic key light from 45 degrees casting sharp Rembrandt triangle shadow on far cheek\n'
  + '   - Sharp specular catch lights visible in both eyes\n\n'
  + '   Color grade: dark cinematic background with ' + registerGrade + '\n'
  + (registerAccent ? '   Accent color hint (use sparingly in clothing or background prop): ' + registerAccent + '\n' : '')
  + '   Detail: photojournalistic quality, candid moment, NOT a posed studio portrait.\n'
  + '   NO text, NO watermarks, NO logos, NO words of any kind in the image.\n'
  + '   === END PHOTOREALISTIC RULES ===\n\n'
  + representationBlock
  + antagonistInstruction
  + '   Emotion guidance for this niche profile (' + nicheKey + '):\n'
  + '   - single_face concept A: ' + emotions.single_a + '\n'
  + '   - single_face concept B: ' + emotions.single_b + '\n'
  + '   - dual_face left person: ' + emotions.dual_left + '\n'
  + '   - dual_face right person: ' + emotions.dual_right + '\n'
  + '   - scene_overlay background: ' + emotions.scene_bg + '\n\n'
  + '   LAYOUT ENFORCEMENT (MANDATORY â€” write these spatial rules verbatim into the image prompt):\n'
  + '   - For single_face: include the literal phrase "subject\'s face is centered at horizontal position 900 of 1280, the entire left 480 pixels are pitch-black empty negative space with NO body parts NO props NO objects".\n'
  + '   - For dual_face: each portrait is exactly 640x720, subject centered, face fills 80% of vertical, NO objects in the lower 100 pixels (reserved for text).\n'
  + '   - For scene_overlay wide scene: include "the upper-left 600x300 zone is the darkest area of the frame, no bright objects or focal subjects in that zone".\n\n'
  + 'Return ONLY valid JSON exactly in this shape:\n'
  + '{"concepts":[{"style":"dual_face","text_format":"stack","text_lines":["WORD1","WORD2"],"emphasis_index":1,"image_prompts":["...","..."]},{"style":"single_face","text_format":"question","text_lines":["ARE YOU","MISSING $5K?"],"emphasis_index":1,"image_prompts":["..."]}]}';

if (countryTarget === 'AU') {
  try {
    var __cbRes = await fetch($env.SUPABASE_URL + '/rest/v1/rpc/render_country_blocks', {
      method: 'POST',
      headers: { apikey: $env.SUPABASE_ANON_KEY, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_country_target: 'AU' })
    });
    if (__cbRes.ok) {
      var __cb = await __cbRes.json();
      var __auAppend = [
        __cb.country_compliance_block || '',
        __cb.country_terminology_block || '',
        __cb.country_calendar_context || '',
        __cb.country_demonetization_constraints || ''
      ].filter(Boolean).join('\n\n');
      if (__auAppend) promptText = promptText + '\n\n=== AU COUNTRY CONTEXT ===\n\n' + __auAppend;
    }
  } catch (_) { }
}

var claudeResp = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: { 'x-api-key': $env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
  body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 3000, messages: [{ role: 'user', content: promptText }] })
});
var claudeResult = await claudeResp.json();
if (!claudeResult.content || !claudeResult.content[0]) {
  throw new Error('Claude API error: ' + JSON.stringify(claudeResult).substring(0, 500));
}

var concepts;
try {
  var text = claudeResult.content[0].text;
  var jsonMatch = text.match(/\{[\s\S]*\}/);
  concepts = JSON.parse(jsonMatch[0]).concepts;
  if (!concepts || concepts.length < 2) throw new Error('Need 2 concepts');
  var validStyles = ['single_face', 'dual_face', 'scene_overlay'];
  var validFormats = ['stack', 'question', 'headline'];
  var formatLimits = { stack: { maxLines: 3, maxChars: 10 }, question: { maxLines: 4, maxChars: 18 }, headline: { maxLines: 3, maxChars: 22 } };
  for (var ci = 0; ci < concepts.length; ci++) {
    var c = concepts[ci];
    if (!validStyles.includes(c.style)) c.style = 'single_face';
    if (!validFormats.includes(c.text_format)) c.text_format = 'stack';
    var lines = c.text_lines || c.text_words || [];
    if (!Array.isArray(lines) || lines.length < 1) throw new Error('Missing text_lines');
    var lim = formatLimits[c.text_format];
    if (lines.length > lim.maxLines) lines = lines.slice(0, lim.maxLines);
    var truncated = false;
    for (var li = 0; li < lines.length; li++) {
      lines[li] = (lines[li] || '').toString().toUpperCase();
      if (lines[li].length > lim.maxChars + 4) { lines[li] = lines[li].substring(0, lim.maxChars); truncated = true; }
    }
    if (truncated) console.log('Variant ' + ci + ': lines truncated to format limit');
    if (c.text_format === 'question') {
      var lastIdx = lines.length - 1;
      if (!lines[lastIdx].endsWith('?')) lines[lastIdx] = lines[lastIdx] + '?';
    }
    c.text_lines = lines;
    c.text_words = lines;
    if (typeof c.emphasis_index !== 'number' || c.emphasis_index >= lines.length) c.emphasis_index = lines.length - 1;
    if (!c.image_prompts || !Array.isArray(c.image_prompts)) throw new Error('Missing image_prompts');
    var expectedCount = c.style === 'single_face' ? 1 : 2;
    if (c.image_prompts.length < expectedCount) throw new Error('Style ' + c.style + ' needs ' + expectedCount + ' prompts, got ' + c.image_prompts.length);
    c.image_prompts = c.image_prompts.slice(0, expectedCount);
  }
  if (concepts[0].style === concepts[1].style) {
    var alt = validStyles.filter(function(s) { return s !== concepts[0].style; });
    console.log('VARIETY VIOLATION: both concepts have style=' + concepts[0].style + '. Forcing B to ' + alt[0] + '. Note: B image_prompts may now mismatch â€” Generate Images will fail loud if so.');
    concepts[1].style = alt[0];
  }
  if (concepts[0].text_format === concepts[1].text_format) {
    var altF = validFormats.filter(function(f) { return f !== concepts[0].text_format; });
    console.log('FORMAT VARIETY: both concepts have text_format=' + concepts[0].text_format + '. Forcing B to ' + altF[0] + '.');
    concepts[1].text_format = altF[0];
  }
} catch (e) {
  throw new Error('Claude parse error: ' + e.message);
}

console.log('A: style=' + concepts[0].style + ' format=' + concepts[0].text_format + ' lines=' + JSON.stringify(concepts[0].text_lines));
console.log('B: style=' + concepts[1].style + ' format=' + concepts[1].text_format + ' lines=' + JSON.stringify(concepts[1].text_lines));

return [{ json: {
  topic_id: topicId,
  project_id: projectId,
  drive_folder_id: topic.drive_folder_id,
  title: title,
  niche: niche,
  niche_profile_used: nicheKey,
  country_target: countryTarget,
  register_id: registerId,
  register_grade_used: registerGrade,
  concepts: concepts
} }];

// Generate AI images via OpenRouter (gpt-image-1) â€” replaces Seedream/Fal.ai
// v3 (2026-04-30 phase 2): better photorealism, RAW DSLR skin texture, layout adherence.
// n8n sandbox disallows 'fs' â€” base64 decode is via execSync stdin into base64 -d.
var execSync = require('child_process').execSync;
var data = $input.first().json;
var topicId = data.topic_id;
var concepts = data.concepts;

var workdir = '/tmp/production/' + topicId + '/thumbnails';
execSync('mkdir -p ' + workdir, { shell: '/bin/sh' });

var fontPath = '/tmp/Montserrat-ExtraBold.ttf';
try {
  execSync('test -f ' + fontPath, { shell: '/bin/sh' });
} catch(e) {
  try {
    execSync('curl -sL -o ' + fontPath + ' "https://github.com/JulietaUla/Montserrat/raw/master/fonts/ttf/Montserrat-ExtraBold.ttf"', { shell: '/bin/sh', timeout: 15000 });
  } catch(e2) {
    fontPath = '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf';
  }
}

var orModel = $env.OPENROUTER_IMAGE_MODEL || 'google/gemini-3-pro-image-preview';
var orHeaders = {
  'Authorization': 'Bearer ' + $env.OPENROUTER_API_KEY,
  'Content-Type': 'application/json',
  'HTTP-Referer': 'https://dashboard.operscale.cloud',
  'X-Title': 'Vision GridAI Thumbnails'
};

// Gemini doesn't take a size param â€” embed aspect ratio in prompt, then FFmpeg crops to target.
var sizeMap = {
  'single_face': [{ aspect: 'landscape 16:9 aspect ratio', target: { w: 1280, h: 720 } }],
  'dual_face': [
    { aspect: 'portrait taller-than-square 8:9 aspect ratio', target: { w: 640, h: 720 } },
    { aspect: 'portrait taller-than-square 8:9 aspect ratio', target: { w: 640, h: 720 } }
  ],
  'scene_overlay': [
    { aspect: 'landscape 16:9 aspect ratio', target: { w: 1280, h: 720 } },
    { aspect: 'square 1:1 aspect ratio', target: { w: 480, h: 480 } }
