var FONT_MIN = 50;
var FONT_MAX = 165;
var EMPH_RATIO = 1.10;
var LINE_SPACING_RATIO = 0.18;

function autoFitFontSize(lines, style) {
  var maxChars = 0;
  for (var i = 0; i < lines.length; i++) {
    if (lines[i].length > maxChars) maxChars = lines[i].length;
  }
  var availWidth = STYLE_WIDTH[style] || 850;
  var lineCount = lines.length;
  var fromWidth = Math.floor(availWidth / Math.max(1, maxChars) / CHAR_WIDTH_FACTOR);
  var lineFactor = lineCount + (lineCount - 1) * LINE_SPACING_RATIO;
  var fromHeight = Math.floor(MAX_TEXT_HEIGHT / Math.max(0.5, lineFactor));
  var f = Math.min(fromWidth, fromHeight, FONT_MAX);
  return Math.max(f, FONT_MIN);
}

