      isEmph = (li2 % 2 === 0);
    } else {
      isEmph = (li2 === emphIdx);
    }
    var fc = isEmph ? pal.emphasisColor : pal.textColor;
    var fs = isEmph ? emphFontSize : fontSize;
    var bw = isEmph ? 6 : 5;
    var safeLine = line.replace(/'/g, '').replace(/:/g, '').replace(/\\/g, '');
    filters.push(
      "drawtext=text='" + safeLine + "'"
      + ":fontfile='" + fontPath + "'"
      + ':fontsize=' + fs
      + ':fontcolor=' + fc
      + ':borderw=' + bw
      + ':bordercolor=' + pal.borderColor
      + ':x=' + textX
      + ':y=' + Math.round(y)
    );
    y += fs + lineSpacing;
  }

  var filterStr = filters.join(',');
  execSync("cat > " + workdir + "/f_" + v + ".txt << 'FEOF'\n" + filterStr + "\nFEOF", { shell: '/bin/sh' });
  execSync('ffmpeg -y -i ' + baseImg + ' -filter_script:v ' + workdir + '/f_' + v + '.txt -frames:v 1 ' + output + ' 2>&1', { shell: '/bin/sh', timeout: 30000 });
  console.log('Thumbnail ' + (v === 0 ? 'A' : 'B') + ' done');
}

var thumbAB64 = execSync('base64 -w0 ' + workdir + '/thumb_a.png', { maxBuffer: 10 * 1024 * 1024 }).toString().trim();
var thumbBB64 = execSync('base64 -w0 ' + workdir + '/thumb_b.png', { maxBuffer: 10 * 1024 * 1024 }).toString().trim();
console.log('Sizes: A=' + Math.round(thumbAB64.length / 1024) + 'KB, B=' + Math.round(thumbBB64.length / 1024) + 'KB');

return [
  { json: { filename: 'thumbnail_option_a.png', drive_folder_id: data.drive_folder_id, topic_id: topicId, project_id: data.project_id, concept: concepts[0], variant: 'A' }, binary: { data: { data: thumbAB64, mimeType: 'image/png', fileName: 'thumbnail_option_a.png' } } },
  { json: { filename: 'thumbnail_option_b.png', drive_folder_id: data.drive_folder_id, topic_id: topicId, project_id: data.project_id, concept: concepts[1], variant: 'B' }, binary: { data: { data: thumbBB64, mimeType: 'image/png', fileName: 'thumbnail_option_b.png' } } }
];

// Update Supabase: set thumbnail_url on topic + log to production_log
var uploads = $('Upload to Drive').all();
var conceptData = $('Generate Concepts').first().json;
var topicId = conceptData.topic_id;
var projectId = conceptData.project_id;

var thumbDetails = uploads.map(function(item, i) {
  var concept = conceptData.concepts[i] || {};
  return {
    variant: i === 0 ? 'A' : 'B',
    style: concept.style || 'single_face',
    drive_file_id: item.json.id,
    drive_file_name: item.json.name,
    web_view_link: item.json.webViewLink,
    web_content_link: item.json.webContentLink,
    text_words: concept.text_words || [],
    emphasis_index: concept.emphasis_index || 0,
    image_prompts: concept.image_prompts || []
  };
});

var primaryUrl = thumbDetails[0].web_view_link || thumbDetails[0].web_content_link || '';

var supabaseHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

var patchResp = await fetch(
  $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId,
  {
    method: 'PATCH',
    headers: supabaseHeaders,
    body: JSON.stringify({ thumbnail_url: primaryUrl, updated_at: new Date().toISOString() })
  }
);
if (!patchResp.ok) console.error('PATCH topics error: ' + patchResp.status);
console.log('Updated topic ' + topicId + ' thumbnail_url');

var logResp = await fetch(
  $env.SUPABASE_URL + '/rest/v1/production_log',
  {
    method: 'POST',
    headers: supabaseHeaders,
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: 'thumbnail',
      action: 'completed',
      details: {
        thumbnails: thumbDetails,
        primary_thumbnail: thumbDetails[0].drive_file_id,
        styles_used: thumbDetails.map(function(t) { return t.style; })
      }
    })
  }
);
if (!logResp.ok) console.error('POST production_log error: ' + logResp.status);
console.log('Production log written');

return [{ json: { success: true, topic_id: topicId, project_id: projectId, thumbnail_url: primaryUrl, thumbnails: thumbDetails } }];
